challenge.solution:
class BaseEvent:
    __slots__ = ('timestamp',)
    def __init__(self, timestamp):
        self.timestamp = timestamp

class ClickEvent(BaseEvent):
    __slots__ = ('button',)
    def __init__(self, timestamp, button):
        super().__init__(timestamp)
        self.button = button

e = ClickEvent(12345, 'left')
print(hasattr(e, '__dict__'))

